            htl.html`&lt;label&gt;&emsp;&lt;/label&gt; 
            &lt;input  
              name=${question} &emsp;
              type="radio"
              value="${opt}"
              checked=${opt === answer}
              onChange=${() =&gt; setAnswer(opt)}
            &gt;
            &lt;/input&gt;`
        )}
      &lt;/form&gt;
      &lt;div&gt;${question}&lt;/div&gt;
      &lt;div&gt; &emsp; ${
       answer === null ? "" : answer === correct ? "✅" : "🔴"
      }&lt;/div&gt;
    &lt;/div&gt;`
    );

    root.value = answer;
    if (!initial) {
      root.dispatchEvent(new CustomEvent("input"));
      onChange(answer);
    }
  }

  setAnswer(null, true);
  return root;
}

